import { HttpClient, HttpHeaders } from "@angular/common/http";
import { ChangeDetectorRef, Component, OnInit, ViewChild } from "@angular/core";
import {
  FormBuilder,
  FormGroup,
  Validators,
  FormControl,
} from "@angular/forms";
import {
  AlertController,
  ModalController,
  Platform,
  ToastController,
} from "@ionic/angular";
import { EnvService } from "src/app/core/services/env.service";
import { LoanTypeRef } from "src/app/views/Models/Loan/LoanType";
import { ILoanCalc } from "src/app/views/Models/Loan/LoanCalc";
import { DatePipe, formatNumber } from "@angular/common";
import { IOfficer } from "../../../Models/Officer/Officer";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { LocationService } from "src/app/core/services/location.service";
import { IClientType } from "../../../Models/Client/ClientType";
import { Subscription } from "rxjs";
import { SearchResult } from "../../../Models/References/SearchResult";
import { ClientInfo } from "../../../Models/Client/ClientInfo";
import { GeolocationResult } from "src/app/core/models/IntentResults/GeolocationResult";
import { LoanInfo } from "src/app/views/Models/Loan/LoanInfo";
import { Router } from "@angular/router";

@Component({
  selector: "app-loan-field-review",
  templateUrl: "./loan-field-review.page.html",
  styleUrls: ["./loan-field-review.page.css"],
})
export class LoanFieldReviewPage {
  constructor(
    public formBuilder: FormBuilder,
    private env: EnvService,
    private alert: AlertService,
    private http: HttpClient,
    private alertController: AlertController,
    private authService: MohassilAuthService,
    private locationService: LocationService,
    private modal: ModalController,
    private cdref: ChangeDetectorRef,
    private toastController: ToastController,
    private datePipe: DatePipe,
    private platform: Platform,
    private router: Router
  ) {}

  showLoader: boolean = false;
  isLoanForm: boolean = false;
  isSearching: boolean = true;
  backButtonListener: Subscription;
  home_lat: string = null;
  home_long: string = null;
  home_zoom: string = null;
  bus_lat: string = null;
  bus_long: string = null;
  bus_zoom: string = null;
  org_code_userinfo: string;
  branch_code_userinfo: string;
  officer_key_userinfo: string;
  user_name_userinfo: string;
  job_code_userinfo: string;
  notes: string = null;

  page: number = 1; // the page we are viewing
  pageSize = 10; // number of viewed results
  count: number = 1;
  sortingParam: string = "application_code";
  orderBy: boolean = false;
  RandomSelection: number = 0;

  //#region Models
  clientInfo: ClientInfo;
  SearchResult: SearchResult;
  LoanInfo: LoanInfo;
  //#endregion

  ngOnInit() {
    this.registerBackButtonListener();
    this.authService.getUserInfo().then((userInfo) => {
      this.branch_code_userinfo = userInfo.branch_code;
      this.org_code_userinfo = userInfo.org_code;
      this.officer_key_userinfo = userInfo.officer_key;
      this.user_name_userinfo = userInfo.user_name;
      this.job_code_userinfo = userInfo.job_code;
    });
  }

  ngOnDestroy(): void {
    this.backButtonListener.unsubscribe();
  }

  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        this.backButton();
      }
    );
  }

  backButton(): void {
    if (this.isLoanForm == true) {
      this.BackToSearchForm();
    } else {
      this.router.navigate(["/home"]);
    }
  }

  ngAfterContentChecked() {
    this.cdref.detectChanges();
  }

  clientSelected(searchResult: SearchResult) {
    this.isSearching = false;
    this.isLoanForm = true;
    this.SearchResult = searchResult;
    this.GetClientInfo(searchResult);
  }

  GetClientInfo(i: SearchResult) {
    console.log("clientSEARCH", i);
    this.showLoader = true;
    this.http
      .get<ClientInfo>(
        this.env.API_URL +
          `api/Clients/GetClientByKey?clientKey=${i.client_key}`
      )
      .subscribe({
        next: (data_1) => {
          this.http
            .post<ClientInfo>(this.env.API_URL + "api/Clients/GetClientById", {
              nation_id: data_1.nation_id,
            })
            .subscribe(async (data) => {
              this.clientInfo = data["result"][0];
              if (!this.clientInfo) {
                this.clientInfo = data_1;
              }
              // this.home_lat = this.clientInfo.home_Lat;
              // this.home_long = this.clientInfo.home_Long;
              // this.home_zoom = this.clientInfo.home_Zoom;
              // this.bus_lat = this.clientInfo.bus_Lat;
              // this.bus_long = this.clientInfo.bus_Long;
              // this.bus_zoom = this.clientInfo.bus_Zoom;
              this.showLoader = false;
              console.log("ClientInfo", this.clientInfo);
              this.GetLoanInfo(i);
            });
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  GetLoanInfo(searchResult: SearchResult) {
    this.showLoader = true;
    this.http
      .post<LoanInfo>(this.env.API_URL + "api/Loan/GetLoanInfo", {
        org_code: this.org_code_userinfo,
        branch_code: this.branch_code_userinfo,
        client_Code: searchResult.client_code.toString(),
        org_branch_code: searchResult.org_branch_code.toString(),
        loan_code: searchResult.loan_code.toString(),
      })
      .subscribe({
        next: (data) => {
          this.LoanInfo = data[0];
          console.log("LoanInfo", this.LoanInfo);
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  ShowHomeLocation() {
    this.locationService.showLocation(
      this.clientInfo.home_Lat + "," + this.clientInfo.home_Long
    );
  }
  async GetHomeLocation() {
    this.showLoader = true;
    try {
      let locationResult: GeolocationResult =
        await this.locationService.getLocation();
      console.log(locationResult);
      if (!locationResult.success) {
        this.showAlertNoReload(locationResult.message);
        this.showLoader = false;
        return;
      }
      this.home_lat = locationResult.position?.coords.latitude.toString();
      this.home_long = locationResult.position?.coords.longitude.toString();
      this.home_zoom = "0";
      this.presentToast("تم", locationResult.message);
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      this.showAlertNoReload("خطأ عند أخذ لقطة الموقع");
    }
  }
  ShowBusLocation() {
    this.locationService.showLocation(
      this.clientInfo.bus_Lat + "," + this.clientInfo.bus_Long
    );
  }
  async GetBusLocation() {
    this.showLoader = true;
    try {
      let locationResult: GeolocationResult =
        await this.locationService.getLocation();
      console.log(locationResult);
      if (!locationResult.success) {
        this.showAlertNoReload(locationResult.message);
        this.showLoader = false;
        return;
      }
      this.bus_lat = locationResult.position?.coords.latitude.toString();
      this.bus_long = locationResult.position?.coords.longitude.toString();
      this.bus_zoom = "0";
      this.presentToast("تم", locationResult.message);
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      this.showAlertNoReload("خطأ عند أخذ لقطة الموقع");
    }
  }

  submit() {
    this.showLoader = true;
    this.notes = this.LoanForm.value.notes;
    this.http
      .post(this.env.API_URL + "api/Loan/InsertLoanFieldVisit", {
        org_code: this.org_code_userinfo,
        branch_code: this.branch_code_userinfo,
        application_key: this.LoanInfo.application_key.toString(),
        officer_key: this.officer_key_userinfo,
        user_name: this.user_name_userinfo,
        uuc_appl: null,
        job_code: this.job_code_userinfo,
        visit_date: this.datePipe.transform(new Date(), "yyyy-MM-dd"),
        home_lat: this.home_lat,
        home_long: this.home_long,
        home_Zoom: this.home_zoom,
        bus_lat: this.bus_lat,
        bus_long: this.bus_long,
        bus_Zoom: this.bus_zoom,
        notes: this.notes,
      })
      .subscribe({
        next: (data) => {
          this.showLoader = false;
          this.showAlert("لقد تم المراجعة بنجاح");
        },
        error: (err) => {
          this.showLoader = false;
          this.showAlertNoReload("خطأ في : " + err);
          console.log("err", err);
        },
      });
  }

  BackToSearchForm() {
    this.isLoanForm = false;
    this.isSearching = true;
  }

  cancel() {
    this.home_lat = null;
    this.home_long = null;
    this.home_zoom = null;
    this.bus_lat = null;
    this.bus_long = null;
    this.bus_zoom = null;
    this.clientInfo = null;
    this.SearchResult = null;
    this.LoanInfo = null;
    this.LoanForm.patchValue({ notes: null });
    this.isLoanForm = false;
    this.isSearching = true;
  }
  checker(input: string) {
    if (input == null) return "لا يوجد";
    else {
      if (input.includes("00:00:00")) {
        return input.split(" ")[0];
      } else {
        return input;
      }
    }
  }
  LoanForm: FormGroup = this.formBuilder.group({
    notes: [null],
  });
  async showAlertNoReload(message: string): Promise<void> {
    let alert = this.alertController.create({
      header: "تنبيه",
      message: message,
      buttons: [
        {
          text: "OK",
          role: "OK",
        },
      ],
    });
    (await alert).present();
  }
  async presentToast(header: string, message: string): Promise<void> {
    let toast = await this.toastController.create({
      header: header,
      message: message,
      cssClass: "toast-primary",
      duration: 2000,
      position: "bottom",
    });

    await toast.present();
  }
  async showAlert(message: string): Promise<void> {
    let alert = this.alertController.create({
      header: "تنبيه",
      message: message,
      buttons: [
        {
          text: "OK",
          role: "OK",
          handler: () => {
            location.reload();
          },
        },
      ],
    });
    (await alert).present();
  }
  async SaveAlert(): Promise<void> {
    this.notes = this.LoanForm.value.notes;
    if (
      ((this.home_lat && this.home_long && this.home_zoom) ||
        (this.bus_lat && this.bus_long && this.bus_zoom)) != null &&
      this.notes != null
    ) {
      let alert = this.alertController.create({
        header: "تنبيه",
        message: "هل أنت متأكد أنك تريد تنفيذ هذة العملية؟ ",
        buttons: [
          {
            text: "نعم",
            role: "OK",
            cssClass: "btn-success",
            handler: () => {
              this.submit();
            },
          },
          {
            text: "لا",
            cssClass: "btn-danger",
            role: "cancel",
            handler: () => {},
          },
        ],
      });
      (await alert).present();
    } else {
      if (this.notes == null) {
        this.presentToast("خطأ", "يجب اضافة ملاحظات الزيارة");
      }
      if (
        ((this.home_lat && this.home_long && this.home_zoom) ||
          (this.bus_lat && this.bus_long && this.bus_zoom)) == null
      ) {
        this.presentToast("خطأ", "يجب أخذ لقطة للمنزل او للعمل");
      }
    }
  }
}
